# Plan: Add `next/geo` Utility Module

## Context

Next.js middleware and edge functions already expose a `userAgent()` helper via `next/server`. CDN providers (Vercel, Cloudflare) inject geolocation data into request headers, but there is no first-class Next.js utility to parse them. This plan adds a `next/geo` public module that follows the exact same patterns as `next/server`'s `userAgent` exports.

---

## Files to Create / Modify

| Action   | Path |
|----------|------|
| **Create** | `packages/next/src/server/web/spec-extension/geo.ts` |
| **Create** | `packages/next/geo.js` |
| **Create** | `packages/next/geo.d.ts` |
| **Modify** | `packages/next/package.json` (add to `files` array) |
| **Create** | `packages/next/src/server/web/spec-extension/geo.test.ts` |

---

## Step-by-Step Implementation

### Step 1 — Core implementation: `packages/next/src/server/web/spec-extension/geo.ts`

Mirrors the structure of `user-agent.ts` (same file, same directory). No external imports needed.

```typescript
export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  AU: 'Australia',
  BR: 'Brazil',
  CA: 'Canada',
  CN: 'China',
  DE: 'Germany',
  FR: 'France',
  GB: 'United Kingdom',
  IN: 'India',
  JP: 'Japan',
  US: 'United States',
}

export function geoFromHeaders(headers: Headers): Geo {
  const countryCode =
    headers.get('x-vercel-ip-country') ??
    headers.get('cf-ipcountry') ??
    undefined

  return {
    city: headers.get('x-vercel-ip-city') ?? undefined,
    countryCode,
    country: countryCode ? COUNTRY_NAMES[countryCode.toUpperCase()] : undefined,
    region: headers.get('x-vercel-ip-country-region') ?? undefined,
    latitude: headers.get('x-vercel-ip-latitude') ?? undefined,
    longitude: headers.get('x-vercel-ip-longitude') ?? undefined,
    timezone: headers.get('x-vercel-ip-timezone') ?? undefined,
  }
}

export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

export function isInRegion(geo: Geo, regions: string[]): boolean {
  if (!geo.countryCode) return false
  const code = geo.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth radius in km
  const toRad = (deg: number): number => (deg * Math.PI) / 180
  const φ1 = toRad(parseFloat(lat1))
  const φ2 = toRad(parseFloat(lat2))
  const dφ = toRad(parseFloat(lat2) - parseFloat(lat1))
  const dλ = toRad(parseFloat(lon2) - parseFloat(lon1))
  const a =
    Math.sin(dφ / 2) ** 2 +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(dλ / 2) ** 2
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
}
```

Key design notes:
- `geo()` wraps `geoFromHeaders()` exactly as `userAgent()` wraps `userAgentFromString()`.
- `headers.get()` returns `null` for missing headers; use `?? undefined` to strip nulls from the interface fields.
- `countryCode` is computed once and reused for the `country` lookup.
- No imports required — pure TypeScript, no `ua-parser-js` equivalent needed.

---

### Step 2 — Public entry point: `packages/next/geo.js`

Follows the exact pattern of `packages/next/server.js` (lines 1–30):

```javascript
const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders: require('next/dist/server/web/spec-extension/geo').geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
// When importing CommonJS modules, the module.exports object is provided as the default export
module.exports = geoExports

// make import { xxx } from 'next/geo' work
exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance
```

---

### Step 3 — Type definitions: `packages/next/geo.d.ts`

Follows the pattern of `packages/next/server.d.ts` (re-export from `next/dist/...`):

```typescript
export type { Geo } from 'next/dist/server/web/spec-extension/geo'
export { geo } from 'next/dist/server/web/spec-extension/geo'
export { geoFromHeaders } from 'next/dist/server/web/spec-extension/geo'
export { isInRegion } from 'next/dist/server/web/spec-extension/geo'
export { geoDistance } from 'next/dist/server/web/spec-extension/geo'
```

---

### Step 4 — Register in `packages/next/package.json`

In the `"files"` array (currently lines 11–76), insert after `"form.d.ts"` (line 43) — alphabetically `g` follows `f`:

```json
    "form.js",
    "form.d.ts",
    "geo.js",        // ← add
    "geo.d.ts",      // ← add
    "router.js",
```

No other changes to `package.json`.

---

### Step 5 — Test file: `packages/next/src/server/web/spec-extension/geo.test.ts`

Uses Jest (same framework as `adapters/headers.test.ts` in the same tree — `describe` / `it` / `expect`):

```typescript
import {
  geo,
  geoFromHeaders,
  isInRegion,
  geoDistance,
} from './geo'

describe('geo', () => {
  it('extracts Vercel geolocation headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'New York',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'NY',
      'x-vercel-ip-latitude': '40.7128',
      'x-vercel-ip-longitude': '-74.0060',
      'x-vercel-ip-timezone': 'America/New_York',
    })
    const result = geo({ headers })
    expect(result.city).toBe('New York')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('NY')
    expect(result.latitude).toBe('40.7128')
    expect(result.longitude).toBe('-74.0060')
    expect(result.timezone).toBe('America/New_York')
  })

  it('returns undefined fields when headers are missing', () => {
    const result = geo({ headers: new Headers() })
    expect(result.city).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
  })
})

describe('geoFromHeaders', () => {
  it('falls back to cf-ipcountry when Vercel header is absent', () => {
    const headers = new Headers({ 'cf-ipcountry': 'GB' })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'DE',
      'cf-ipcountry': 'FR',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('returns undefined country for unknown countryCode', () => {
    const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('isInRegion', () => {
  it('returns true when countryCode matches (case-insensitive)', () => {
    expect(isInRegion({ countryCode: 'US' }, ['us', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'ca' }, ['CA', 'US'])).toBe(true)
  })

  it('returns false when countryCode does not match', () => {
    expect(isInRegion({ countryCode: 'DE' }, ['US', 'GB'])).toBe(false)
  })

  it('returns false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US'])).toBe(false)
  })
})

describe('geoDistance', () => {
  it('calculates distance between New York and London within 50 km', () => {
    // NY: 40.7128 N, 74.0060 W  |  London: 51.5074 N, 0.1278 W
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(dist).toBeGreaterThan(5520)
    expect(dist).toBeLessThan(5620)
  })

  it('returns 0 for identical points', () => {
    expect(geoDistance('48.8566', '2.3522', '48.8566', '2.3522')).toBeCloseTo(0)
  })
})
```

---

## Reference Files (read during exploration)

| File | Purpose |
|------|---------|
| `packages/next/server.js` | Template for `geo.js` entry point pattern |
| `packages/next/server.d.ts` | Template for `geo.d.ts` re-export pattern |
| `packages/next/src/server/web/spec-extension/user-agent.ts` | Template for `geo.ts` implementation structure |
| `packages/next/package.json` lines 11–76 | `files` array insertion point |
| `packages/next/src/server/web/spec-extension/adapters/headers.test.ts` | Jest test pattern used in this directory |

---

## Verification

1. **TypeScript check** (fastest, ~10s):
   ```bash
   pnpm --filter=next types
   ```

2. **Build** (compiles `geo.ts` → `dist/server/web/spec-extension/geo.js`):
   ```bash
   pnpm --filter=next build
   ```

3. **Unit tests**:
